const announcements = [];

for (const item of $input.all()) {
  const message = item.json;

  announcements.push({
    id: message.id,
    content: message.content,
    author: message.author.username,
    timestamp: message.timestamp,
    url: `https://discord.com/channels/${message.guild_id}/${message.channel_id}/${message.id}`,
    attachments: message.attachments || [],
    embeds: message.embeds || []
  });
}

// Sort by timestamp, newest first
announcements.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

return [{ json: { announcements } }];

const announcements = $input.first().json.announcements;

// Helper function to escape JSX content
function escapeJSX(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;')
    .replace(/\{/g, '&#123;')
    .replace(/\}/g, '&#125;');
}

// Helper function to format Discord markdown to HTML
function formatContent(content) {
  if (!content) return '';

  let formatted = escapeJSX(content);

  // Convert Discord markdown
  formatted = formatted
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>') // Bold
    .replace(/\*(.+?)\*/g, '<em>$1</em>') // Italic
    .replace(/\n/g, '<br />'); // Line breaks

  return formatted;
}

// Generate JSX content
const jsxContent = `export const DiscordAnnouncements = () => {
  const announcements = [
${announcements.map(ann => `    {
      id: "${ann.id}",
      content: "${formatContent(ann.content)}",
      author: "${escapeJSX(ann.author)}",
      timestamp: "${ann.timestamp}",
      url: "${ann.url}"
    }`).join(',\n')}
  ];

  return (
    <div className="discord-announcements">
      <div className="announcements-header">
        <h3>Latest Livepeer Announcements</h3>
        <p className="text-sm text-gray-600">From Discord</p>
      </div>
      <div className="announcements-list space-y-4 mt-4">
        {announcements.map((announcement) => (
          <div key={announcement.id} className="announcement-card border rounded-lg p-4">
            <div className="announcement-meta flex items-center gap-2 text-sm text-gray-600 mb-2">
              <span className="font-semibold">{announcement.author}</span>
              <span>•</span>
              <time dateTime={announcement.timestamp}>
                {new Date(announcement.timestamp).toLocaleDateString('en-US', {
                  month: 'short',
                  day: 'numeric',
                  year: 'numeric'
                })}
              </time>
            </div>
            <div 
              className="announcement-content" 
              dangerouslySetInnerHTML={{ __html: announcement.content }}
            />
            <a 
              href={announcement.url} 
              target="_blank" 
              rel="noopener noreferrer"
              className="text-sm text-blue-600 hover:text-blue-800 mt-2 inline-block"
            >
              View in Discord →
            </a>
          </div>
        ))}
      </div>
    </div>
  );
};
`;

return [{ json: { content: jsxContent, announcements } }];
